/**
 * Bundle Supabase SDK for Chrome Extension
 *
 * This script creates a standalone bundle of @supabase/supabase-js
 * that can be used in Chrome extension content scripts without CSP violations.
 */

const fs = require('fs');
const path = require('path');

// Read the Supabase UMD bundle from node_modules
const supabasePath = path.join(__dirname, '../node_modules/@supabase/supabase-js/dist/umd/supabase.js');
const outputPath = path.join(__dirname, '../content/lib/supabase.js');

console.log('🔨 Bundling Supabase SDK for Chrome Extension...');

try {
  // Check if source file exists
  if (!fs.existsSync(supabasePath)) {
    console.error('❌ Supabase UMD bundle not found at:', supabasePath);
    console.log('Available files in @supabase/supabase-js/dist:');
    const distPath = path.join(__dirname, '../node_modules/@supabase/supabase-js/dist');
    if (fs.existsSync(distPath)) {
      console.log(fs.readdirSync(distPath));
    }
    process.exit(1);
  }

  // Read the Supabase bundle
  let supabaseCode = fs.readFileSync(supabasePath, 'utf8');

  // Wrap in IIFE to avoid global scope pollution
  const wrappedCode = `/**
 * Supabase Client Library (Bundled for Chrome Extension)
 * Auto-generated by scripts/bundle-supabase.js
 * DO NOT EDIT THIS FILE MANUALLY
 */

(function() {
  'use strict';

  ${supabaseCode}

  // Export to window for Chrome extension content scripts
  if (typeof window !== 'undefined' && typeof supabase !== 'undefined') {
    window.supabase = supabase;
    console.log('✅ Supabase SDK loaded successfully');
  }
})();
`;

  // Ensure output directory exists
  const outputDir = path.dirname(outputPath);
  if (!fs.existsSync(outputDir)) {
    fs.mkdirSync(outputDir, { recursive: true });
  }

  // Write bundled file
  fs.writeFileSync(outputPath, wrappedCode, 'utf8');

  console.log('✅ Supabase SDK bundled successfully!');
  console.log('📦 Output:', outputPath);
  console.log('📏 Size:', (wrappedCode.length / 1024).toFixed(2), 'KB');

} catch (error) {
  console.error('❌ Error bundling Supabase:', error.message);
  process.exit(1);
}
